const token = env.get("INFLUX_TOKEN") || "my-super-secret-admin-token-ChangeMe-12345";
const rawDb = env.get("INFLUX_DATABASE") || "energy_monitoring";

// We want to verify and seed three databases:
const databases = [
    { name: rawDb, retention: 0 },
    { name: "energy_minutes", retention: 1209600 }, // 14 days in seconds
    { name: "energy_hour", retention: 0 }           // permanent
];

// Send 3 separate messages to the next HTTP request node
const msgs = databases.map(db => {
    return {
        dbName: db.name,
        retention: db.retention,
        headers: {
            "Authorization": "Token " + token
        }
    };
});

return [ msgs ];

const token = env.get("INFLUX_TOKEN") || "my-super-secret-admin-token-ChangeMe-12345";

const buckets = msg.payload.buckets || [];
const dbExists = buckets.some(b => b.name === msg.dbName);

if (dbExists) {
    node.status({ fill: "green", shape: "dot", text: `${msg.dbName} exists ✓` });
    node.log(`Database '${msg.dbName}' already exists.`);
    return null; // Stop this message
}

node.status({ fill: "yellow", shape: "ring", text: `Creating ${msg.dbName}...` });

// Prepare create request
msg.url = "http://influxdb:8181/api/v2/buckets";
msg.headers = {
    "Authorization": "Token " + token,
    "Content-Type": "application/json"
};
msg.payload = {
    "name": msg.dbName
};
if (msg.retention > 0) {
    msg.payload.retentionRules = [
        {
            "type": "expire",
            "everySeconds": msg.retention
        }
    ];
} else {
    msg.payload.retentionRules = [];
}
return msg;

// Simulate energy data for multiple machines
const machines = [
    { machine_id: 'machine_001', location: 'line_a' },
    { machine_id: 'machine_002', location: 'line_a' },
    { machine_id: 'machine_003', location: 'line_b' },
];

const timestampNs = Date.now() * 1000000; // Nanosecond timestamp
const mqttMsgs = [];
const lpLines = [];

machines.forEach(m => {
    const power_kw     = parseFloat((10 + Math.random() * 20).toFixed(3));
    const energy_kwh   = parseFloat((context.get(m.machine_id + '_kwh') || 1000.0 + Math.random() * 0.03).toFixed(4));
    const voltage_v    = parseFloat((219 + Math.random() * 3).toFixed(2));
    const current_a    = parseFloat((power_kw * 1000 / (voltage_v * Math.sqrt(3)) ).toFixed(3));
    const power_factor = parseFloat((0.92 + Math.random() * 0.06).toFixed(3));

    // Accumulate energy (simulated meter reading)
    context.set(m.machine_id + '_kwh', energy_kwh + power_kw / 360);

    const payloadObj = {
        machine_id:   m.machine_id,
        location:     m.location,
        timestamp:    Date.now(),
        power_kw,
        energy_kwh,
        voltage_v,
        current_a,
        power_factor,
    };

    // MQTT Format
    mqttMsgs.push({
        topic: `factory/${m.location}/${m.machine_id}/energy`,
        payload: JSON.stringify(payloadObj),
        qos: 1,
        retain: false
    });

    // InfluxDB Line Protocol Format
    lpLines.push(`energy_raw,machine_id=${m.machine_id},location=${m.location} power_kw=${power_kw},energy_kwh=${energy_kwh},voltage_v=${voltage_v},current_a=${current_a},power_factor=${power_factor} ${timestampNs}`);
});

// Message 1 (output 1): For InfluxDB HTTP Request
const token = env.get("INFLUX_TOKEN") || "my-super-secret-admin-token-ChangeMe-12345";
const dbName = env.get("INFLUX_DATABASE") || "energy_monitoring";

const msgInflux = {
    url: `http://influxdb:8181/api/v3/write_lp?db=${dbName}&precision=ns`,
    headers: {
        "Authorization": "Token " + token,
        "Content-Type": "text/plain; charset=utf-8"
    },
    payload: lpLines.join("\n")
};

// Message 2 (output 2): For MQTT Publish (as array of messages)
const msgMqtt = [mqttMsgs]; 

return [msgInflux, msgMqtt];

const token = env.get("INFLUX_TOKEN") || "my-super-secret-admin-token-ChangeMe-12345";
const dbName = env.get("INFLUX_DATABASE") || "energy_monitoring";
const offsetSec = parseInt(env.get("AGG_MINUTE_OFFSET_SEC") || "5");

// Checkpoint management
const nowSec = Math.floor(Date.now() / 1000) - offsetSec;
const lastSec = flow.get("last_minute_checkpoint") || (nowSec - 120); // default to 2m ago

if (nowSec <= lastSec) {
    return null; // No new window
}

// Format timestamps to ISO-8601 for SQL queries
const fromStr = new Date(lastSec * 1000).toISOString();
const toStr = new Date(nowSec * 1000).toISOString();

// Construct SQL Query
const sql = `
    SELECT
        DATE_BIN(INTERVAL '1 minute', time, TIMESTAMP '1970-01-01') AS bucket,
        machine_id,
        location,
        AVG(power_kw)     AS avg_power_kw,
        SUM(energy_kwh)   AS sum_energy_kwh,
        AVG(voltage_v)    AS avg_voltage_v,
        AVG(current_a)    AS avg_current_a,
        AVG(power_factor) AS avg_power_factor,
        MIN(power_kw)     AS min_power_kw,
        MAX(power_kw)     AS max_power_kw
    FROM energy_raw
    WHERE time >= TIMESTAMP '${fromStr}'
      AND time <  TIMESTAMP '${toStr}'
    GROUP BY bucket, machine_id, location
    ORDER BY bucket ASC
`;

// Save transient query end time for checkpoint update on success
msg.transient = {
    nextCheckpoint: nowSec,
    fromStr: fromStr,
    toStr: toStr
};

msg.url = "http://influxdb:8181/api/v3/query";
msg.headers = {
    "Authorization": "Token " + token,
    "Content-Type": "application/json",
    "Accept": "application/json"
};
msg.payload = {
    "query": sql,
    "database": dbName
};

return msg;

const token = env.get("INFLUX_TOKEN") || "my-super-secret-admin-token-ChangeMe-12345";

const rows = msg.payload || [];
if (rows.length === 0) {
    // No new data, just advance checkpoint to avoid re-querying
    flow.set("last_minute_checkpoint", msg.transient.nextCheckpoint);
    node.status({ fill: "blue", shape: "ring", text: "No rows, advanced" });
    return null;
}

const lpLines = [];

rows.forEach(row => {
    const bucketTime = row.bucket;
    if (!bucketTime) return;

    const timestampNs = new Date(bucketTime).getTime() * 1000000;

    const fields = [
        `avg_power_kw=${parseFloat(row.avg_power_kw || 0).toFixed(3)}`,
        `sum_energy_kwh=${parseFloat(row.sum_energy_kwh || 0).toFixed(4)}`,
        `avg_voltage_v=${parseFloat(row.avg_voltage_v || 0).toFixed(2)}`,
        `avg_current_a=${parseFloat(row.avg_current_a || 0).toFixed(3)}`,
        `avg_power_factor=${parseFloat(row.avg_power_factor || 0).toFixed(3)}`,
        `min_power_kw=${parseFloat(row.min_power_kw || 0).toFixed(3)}`,
        `max_power_kw=${parseFloat(row.max_power_kw || 0).toFixed(3)}`
    ].join(",");

    lpLines.push(`energy_minute,machine_id=${row.machine_id},location=${row.location} ${fields} ${timestampNs}`);
});

msg.url = `http://influxdb:8181/api/v3/write_lp?db=energy_minutes&precision=ns`;
msg.headers = {
    "Authorization": "Token " + token,
    "Content-Type": "text/plain; charset=utf-8"
};
msg.payload = lpLines.join("\n");

return msg;

if (msg.statusCode === 204 || msg.statusCode === 200) {
    flow.set("last_minute_checkpoint", msg.transient.nextCheckpoint);
    node.status({ fill: "green", shape: "dot", text: `Checkpointed ${msg.transient.nextCheckpoint}` });
    node.log(`Minute aggregation success, checkpoint updated to: ${new Date(msg.transient.nextCheckpoint * 1000).toISOString()}`);
} else {
    node.status({ fill: "red", shape: "dot", text: "Write failed" });
    node.error("Failed to write minute aggregates to InfluxDB. Status code: " + msg.statusCode);
}
return null;

const token = env.get("INFLUX_TOKEN") || "my-super-secret-admin-token-ChangeMe-12345";
const offsetSec = parseInt(env.get("AGG_HOUR_OFFSET_SEC") || "30");

// Checkpoint management
const nowSec = Math.floor(Date.now() / 1000) - offsetSec;
const lastSec = flow.get("last_hour_checkpoint") || (nowSec - 7200); // default to 2h ago

if (nowSec <= lastSec) {
    return null; // No new window
}

const fromStr = new Date(lastSec * 1000).toISOString();
const toStr = new Date(nowSec * 1000).toISOString();

// Construct SQL Query on energy_minute in energy_minutes DB
const sql = `
    SELECT
        DATE_BIN(INTERVAL '1 hour', time, TIMESTAMP '1970-01-01') AS bucket,
        machine_id,
        location,
        AVG(avg_power_kw)         AS avg_power_kw,
        SUM(sum_energy_kwh)       AS sum_energy_kwh,
        AVG(avg_voltage_v)        AS avg_voltage_v,
        AVG(avg_current_a)        AS avg_current_a,
        AVG(avg_power_factor)     AS avg_power_factor,
        MIN(min_power_kw)         AS min_power_kw,
        MAX(max_power_kw)         AS max_power_kw,
        COUNT(*)                  AS sample_count
    FROM energy_minute
    WHERE time >= TIMESTAMP '${fromStr}'
      AND time <  TIMESTAMP '${toStr}'
    GROUP BY bucket, machine_id, location
    ORDER BY bucket ASC
`;

// Save transient end time for checkpoint update on success
msg.transient = {
    nextCheckpoint: nowSec,
    fromStr: fromStr,
    toStr: toStr
};

msg.url = "http://influxdb:8181/api/v3/query";
msg.headers = {
    "Authorization": "Token " + token,
    "Content-Type": "application/json",
    "Accept": "application/json"
};
msg.payload = {
    "query": sql,
    "database": "energy_minutes"
};

return msg;

const token = env.get("INFLUX_TOKEN") || "my-super-secret-admin-token-ChangeMe-12345";

const rows = msg.payload || [];
if (rows.length === 0) {
    flow.set("last_hour_checkpoint", msg.transient.nextCheckpoint);
    node.status({ fill: "blue", shape: "ring", text: "No rows, advanced" });
    return null;
}

const lpLines = [];

rows.forEach(row => {
    const bucketTime = row.bucket;
    if (!bucketTime) return;

    const timestampNs = new Date(bucketTime).getTime() * 1000000;

    const fields = [
        `avg_power_kw=${parseFloat(row.avg_power_kw || 0).toFixed(3)}`,
        `sum_energy_kwh=${parseFloat(row.sum_energy_kwh || 0).toFixed(4)}`,
        `avg_voltage_v=${parseFloat(row.avg_voltage_v || 0).toFixed(2)}`,
        `avg_current_a=${parseFloat(row.avg_current_a || 0).toFixed(3)}`,
        `avg_power_factor=${parseFloat(row.avg_power_factor || 0).toFixed(3)}`,
        `min_power_kw=${parseFloat(row.min_power_kw || 0).toFixed(3)}`,
        `max_power_kw=${parseFloat(row.max_power_kw || 0).toFixed(3)}`,
        `sample_count=${parseInt(row.sample_count || 0)}`
    ].join(",");

    lpLines.push(`energy_hour,machine_id=${row.machine_id},location=${row.location} ${fields} ${timestampNs}`);
});

msg.url = `http://influxdb:8181/api/v3/write_lp?db=energy_hour&precision=ns`;
msg.headers = {
    "Authorization": "Token " + token,
    "Content-Type": "text/plain; charset=utf-8"
};
msg.payload = lpLines.join("\n");

return msg;

if (msg.statusCode === 204 || msg.statusCode === 200) {
    flow.set("last_hour_checkpoint", msg.transient.nextCheckpoint);
    node.status({ fill: "green", shape: "dot", text: `Checkpointed ${msg.transient.nextCheckpoint}` });
    node.log(`Hour aggregation success, checkpoint updated to: ${new Date(msg.transient.nextCheckpoint * 1000).toISOString()}`);
} else {
    node.status({ fill: "red", shape: "dot", text: "Write failed" });
    node.error("Failed to write hour aggregates to InfluxDB. Status code: " + msg.statusCode);
}
return null;
